from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    subject_data = {}
    for triple in triples:
        if triple.subject not in subject_data:
            subject_data[triple.subject] = []
        subject_data[triple.subject].append(triple)

    # Get the main university subject
    main_subject = triples[0].subject

    # Build sentence parts based on predicate types
    location_parts = []
    university_parts = []
    person_parts = []
    number_parts = []

    for triple in subject_data.get(main_subject, []):
        pred = triple.predicate
        obj = triple.object

        if pred in ['city', 'country', 'location', 'campus']:
            if pred == 'city':
                location_parts.append(f"located in {obj}")
            elif pred == 'country':
                location_parts.append(f"in {obj}")
            elif pred == 'location':
                location_parts.append(f"located in {obj}")
            elif pred == 'campus':
                location_parts.append(f"campus at {obj}")
        elif pred in ['established']:
            university_parts.append(f"established in {obj}")
        elif pred in ['numberOfStudents', 'academicStaffSize', 'staff', 'numberOfUndergraduateStudents', 'numberOfPostgraduateStudents', 'numberOfDoctoralStudents', 'outlookRanking']:
            number_parts.append(f"with {obj} {pred.replace('numberOf', '').replace('StaffSize', ' academic staff').replace('Students', ' students').replace('Staff', ' staff').replace('Ranking', ' in outlook ranking')}")
        elif pred in ['rector', 'dean', 'director', 'president']:
            person_parts.append(f"{pred} is {obj}")
        elif pred in ['latinName', 'nickname']:
            university_parts.append(f"({obj})")
        elif pred in ['motto']:
            university_parts.append(f"motto \"{obj}\"")
        elif pred in ['officialSchoolColour']:
            university_parts.append(f"colours {obj}")
        elif pred in ['sportsOffered']:
            university_parts.append(f"offers {obj}")
        elif pred in ['affiliation']:
            university_parts.append(f"affiliated with {obj}")
        elif pred in ['wasGivenTheTechnicalCampusStatusBy']:
            university_parts.append(f"technical campus status by {obj}")

    # Construct the final sentence
    sentence_parts = [main_subject]

    if location_parts:
        sentence_parts.append(" ".join(location_parts))

    if university_parts:
        sentence_parts.append(" ".join(university_parts))

    if person_parts:
        sentence_parts.append(" ".join(person_parts))

    if number_parts:
        sentence_parts.append(" ".join(number_parts))

    return " ".join(sentence_parts) + "."

# EVOLVE-BLOCK-END

